class Solution:
    def totalNumbers(self, digits):
        from itertools import permutations
        n = len(digits)
        seen = set()
        for i, j, k in permutations(range(n), 3):
            if digits[i] == 0:
                continue
            if digits[k] % 2 != 0:
                continue
            seen.add(digits[i] * 100 + digits[j] * 10 + digits[k])
        return len(seen)

