class Solution:
    def totalNumbers(self, digits):
        from collections import Counter
        cnt = Counter(digits)
        total = 0
        for h in range(1, 10):
            for t in range(0, 10):
                for u in range(0, 10, 2):
                    need = Counter([h, t, u])
                    if all(cnt[v] >= c for v, c in need.items()):
                        total += 1
        return total

