var totalNumbers = function(digits) {
    const cnt = new Array(10).fill(0);
    for (const d of digits) cnt[d]++;
    let total = 0;
    for (let h = 1; h < 10; h++) {
        for (let t = 0; t < 10; t++) {
            for (let u = 0; u < 10; u += 2) {
                const need = new Array(10).fill(0);
                need[h]++; need[t]++; need[u]++;
                let ok = true;
                for (let v = 0; v < 10; v++) {
                    if (need[v] > cnt[v]) { ok = false; break; }
                }
                if (ok) total++;
            }
        }
    }
    return total;
};
